const j = $input.first().json.body || $input.first().json;
if (j.callback_query) {
  const cq = j.callback_query;
  const data = (cq.data || '').toString();
  const m = data.match(/^([AB])([01A]):([a-f0-9]{32})$/);
  if (!m) return [{ json: { valid: false, route: 'none' } }];
  const gate = m[1]; const code = m[2]; const db06_id = m[3];
  const chat_id = cq.message?.chat?.id || 8523155253;
  const is_all = code === 'A';
  const ok = code === '1' || is_all;
  let route;
  if (gate === 'A') route = ok ? 'gateA_go' : 'cancel';
  else route = ok ? 'gateB_go' : 'cancel';
  return [{ json: { valid: true, route, gate, db06_id, reply_text: '', chat_id, set_auto: is_all } }];
}
const msg = j.message || j;
const reply_to = msg.reply_to_message;
const out = { valid: false, route: 'none' };
if (!reply_to) return [{ json: out }];
const orig = reply_to.text || '';
const m2 = orig.match(/gate([AB])\s+db06=([a-f0-9]{32})/i);
if (!m2) return [{ json: out }];
const gate = m2[1].toUpperCase();
const db06_id = m2[2];
const reply_text = (msg.text || '').toString().trim();
if (!reply_text) return [{ json: out }];
const chat_id = msg.chat.id;
const lower = reply_text.toLowerCase();
const approveSet = ['好','ok','同意','通過','可以','讚','y','yes'];
const isApprove = approveSet.includes(lower);
const isRedo = /redo|重跑/i.test(reply_text);
let route;
if (gate === 'A') route = isApprove ? 'gateA_go' : 'gateA_modify';
else { if (isApprove) route = 'gateB_go'; else if (isRedo) route = 'gateB_redo'; else route = 'gateB_hint'; }
return [{ json: { valid: true, route, gate, db06_id, reply_text, chat_id, set_auto: false } }];

const p = $input.first().json;
const r = $('Parse Reply').first().json;
const ai_mode = p.properties['ai模式']?.select?.name || '';
let runner_url;
const _b = 'https://makesense.zeabur.app/webhook/';
if (ai_mode.includes('聯想')) runner_url = _b + 'db06-lianxiang-traversal';
else if (ai_mode.includes('搜查')) runner_url = _b + 'db06-search';
else if (ai_mode.includes('分析')) runner_url = _b + 'db06-analyze';
else if (ai_mode.includes('文案')) runner_url = _b + 'db06-copy';
else if (ai_mode.includes('檢核')) runner_url = _b + 'db06-check';
else runner_url = _b + 'db06-plan';
return [{ json: {
  ...r,
  ai_mode,
  runner_url,
  exec_idea: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  sort_num: p.properties['排序']?.number,
  db05_id: (function(){ var T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"]; for(var i=0;i<T.length;i++){var a=p.properties[T[i]]?.relation||[]; if(a.length) return (a[0].id||'').replace(/-/g,'');} return ''; })(),
  target_rel: (function(){ var T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"]; for(var i=0;i<T.length;i++){var a=p.properties[T[i]]?.relation||[]; if(a.length) return T[i];} return ''; })()
}}];

const j = $('Parse DB06').first().json;
const NH = {
  'Authorization': 'Bearer ' + $env.NOTION_INTEGRATION_TOKEN,
  'Notion-Version': '2022-06-28',
  'Content-Type': 'application/json'
};
const now = new Date(Date.now() + 8*3600*1000).toISOString().slice(0,16).replace('T',' ');
const userFeedback = (j.reply_text || '').toString().trim();

// 1. PATCH DB06 執行構想 (overwrite with user feedback)
await this.helpers.httpRequest({
  method: 'PATCH',
  url: 'https://api.notion.com/v1/pages/' + j.db06_id,
  headers: NH,
  body: { properties: { '執行構想': { rich_text: [{ text: { content: userFeedback.slice(0, 1990) } }] } } },
  json: true
});

// 2. PATCH target page 執行構想 (prepend with timestamp, keep old content)
if (j.db05_id) {
  let oldIdea = '';
  try {
    const tp = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.notion.com/v1/pages/' + j.db05_id, headers: NH, json: true });
    oldIdea = ((tp.properties['執行構想'] && tp.properties['執行構想'].rich_text) || []).map(t => t.plain_text).join('');
  } catch(e) {}
  const stamp = '── ' + now + ' 回饋 ──\n' + userFeedback;
  const newIdea = (stamp + (oldIdea ? '\n\n' + oldIdea : '')).slice(0, 1990);
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: 'https://api.notion.com/v1/pages/' + j.db05_id,
    headers: NH,
    body: { properties: { '執行構想': { rich_text: [{ text: { content: newIdea } }] } } },
    json: true
  });
}

return [{ json: j }];

const row = $input.first().json || {};
const j = $('Parse DB06').first().json;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const sanitize = s => (s || '').toString()
