  .replace(/[\u2010-\u2027\u2030-\u205E]/g, ' ')
  .replace(/[\uFF00-\uFF0F\uFF1A-\uFF20\uFF3B-\uFF40\uFF5B-\uFF65]/g, ' ')
  .replace(/[\u3000-\u3017\u301D-\u303F]/g, ' ')
