  'gateA db06=' + j.db06_id;
return [{ json: { chat_id: j.chat_id, flow_id: j.db05_id, reply_to, tg_message: msg, cb_ok: 'A1:' + j.db06_id, cb_all: 'AA:' + j.db06_id } }];

