const row = $input.first().json || {};
const auto_mode = row.auto_mode === true;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const results = $('Query DB06 next').first().json.results || [];
const chat_id = $('Parse DB06').first().json.chat_id;
const db05_id = $('Parse DB06').first().json.db05_id;
const sanitize = s => (s || '').toString()
  .replace(/[/\\:<>#@[\]{}|^`*_~"']/g, ' ')
  .replace(/[\u2010-\u2027\u2030-\u205E]/g, ' ')
  .replace(/[\uFF00-\uFF0F\uFF1A-\uFF20\uFF3B-\uFF40\uFF5B-\uFF65]/g, ' ')
  .replace(/[\u3000-\u3017\u301D-\u303F]/g, ' ')
  .replace(/\s+/g, ' ').trim().slice(0, 1500);
const total = results.length;
const done = results.filter(p => (p.properties['ai狀態']?.status?.name||'') === '完成').length;
const pending = results.filter(p => (p.properties['ai狀態']?.status?.name||'') !== '完成');
if (pending.length === 0) {
  return [{ json: { has_next: false, auto_mode, reply_to, flow_id: db05_id, db06_id: '', chat_id, tg_message: '全套完成 共 ' + total + ' 棒已全部通過。', cb_ok: 'noop', cb_all: 'noop', runner_url: '' } }];
}
const p = pending[0];
const db06_id = p.id.replace(/-/g, '');
const raw_mode = p.properties['ai模式']?.select?.name || '';
const ai_mode = sanitize(raw_mode);
let runner_url;
if (raw_mode.includes('聯想')) runner_url = 'https://makesense.zeabur.app/webhook/db06-lianxiang-traversal';
else if (raw_mode.includes('搜查')) runner_url = 'https://makesense.zeabur.app/webhook/db06-search';
else if (raw_mode.includes('分析')) runner_url = 'https://makesense.zeabur.app/webhook/db06-analyze';
else if (raw_mode.includes('文案')) runner_url = 'https://makesense.zeabur.app/webhook/db06-copy';
else if (raw_mode.includes('檢核')) runner_url = 'https://makesense.zeabur.app/webhook/db06-check';
else runner_url = 'https://makesense.zeabur.app/webhook/db06-plan';
const sort_num = p.properties['排序']?.number;
const exec_idea = p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '';
const idea_show = exec_idea ? sanitize(exec_idea) : '(執行構想為空,將用該棒預設工作指示)';
const base = '關卡A 執行前確認\n' +
  '第 ' + (sort_num != null ? sort_num : '?') + ' 棒 (' + ai_mode + ')。全套 ' + total + ' 棒,已完成 ' + done + ' 棒。\n' +
  'DB06 頁面 ' + db06_id + '\n\n' +
  '本棒預定執行構想:\n' + idea_show;
const manual_msg = base + '\n\n按 OK 放行這一關,按 OK ALL 之後全自動。要改執行構想 skip stop 請打字 reply。\ngateA db06=' + db06_id;
const auto_msg = base + '\n\n[全自動模式] 自動執行本棒,免按。';
return [{ json: { has_next: true, auto_mode, reply_to, flow_id: db05_id, db06_id, chat_id, runner_url, tg_message: auto_mode ? auto_msg : manual_msg, cb_ok: 'A1:' + db06_id, cb_all: 'AA:' + db06_id } }];

const mid = ($input.first().json.result?.message_id || '').toString();
const g = $('Pick next pending').first().json;
return [{ json: { flow_id: g.flow_id, last_msg_id: mid, has_next: g.has_next, runner_url: g.runner_url, db06_id: g.db06_id } }];
